const data = $input.first().json;
const phone = data.from || data.phone || "";
const rawMessage = data.body || data.text || "";
const message = rawMessage.toLowerCase().trim();
const timestamp = new Date().toISOString();
let intent = "";
if (message.match(/hi|hello|hey|hii|namaste|namaskar/)) intent = "greeting";
else if (message.match(/price|cost|charge|rate|fees|kitna|kitne paisa/)) intent = "pricing_query";
else if (message.match(/timing|time|open|close|kab|delivery|hours|kitne din/)) intent = "timing_query";
else if (message.match(/order|status|ready|delivery|pickup|mera order/)) intent = "order_status";
else if (message.match(/service|product|available|stitching|alteration|blouse|suit|lehenga|kurti|dress/)) intent = "product_service_guidance";
else if (message.match(/complaint|problem|issue|kharab|galat|late|angry|disappointed/)) intent = "complaint";
else if (message.match(/refund|return|paise wapas|money back/)) intent = "refund_request";
else if (message.match(/call|phone|baat|owner se baat|callback/)) intent = "callback_request";
else if (message.match(/angry|frustrated|upset|irritated|naraaz/)) intent = "angry_customer";
else if (message.match(/cancel|cancellation|cancel order|cancel kar do/)) intent = "cancellation_request";
else if (message.match(/legal|lawyer|court|police|threat|complaint register/)) intent = "legal_threat";
else intent = "unknown";
return [{ json: { phone, raw_message: rawMessage, message, timestamp, intent } }];

const input = $input.first().json;
const message = input.message;
const kbItems = $items("KB Lookup");
let kbReply = "";
for (const item of kbItems) {
  const keywords = (item.json.keywords || "").toLowerCase();
  const keywordList = keywords.split(",").map(function(k) { return k.trim(); });
  for (let i = 0; i < keywordList.length; i++) {
    if (message.includes(keywordList[i])) {
      kbReply = item.json.reply || item.json.answer || "";
      break;
    }
  }
  if (kbReply) break;
}
return [{ json: { phone: input.phone, raw_message: input.raw_message, message: input.message, timestamp: input.timestamp, intent: input.intent, kb_reply: kbReply } }];

const input = $input.first().json;
const intent = input.intent;
const phone = input.phone;
const replies = {
  greeting: "Namaste! Kaise help kar sakte hain?",
  pricing_query: "Price item/design par depend karta hai. Aap bata dijiye?",
  timing_query: "Shop timing owner confirm karenge. Aap approx kab visit karna chahte hain?",
  order_status: "Aap apna naam ya order detail bhej dijiye, hum check karke update denge.",
  product_service_guidance: "Hum stitching, alteration aur boutique related enquiries handle karte hain. Aap bataiye kis item ke liye help chahiye?"
};
return [{ json: { phone: phone, intent: intent, rule_reply: replies[intent] || "" } }];

const input = $input.first().json;
const alertMsg = "ALERT: " + input.intent.toUpperCase() + "
Phone: " + input.phone + "
Message: " + input.raw_message + "
Time: " + new Date().toISOString();
return [{ json: { phone: input.phone, intent: input.intent, alert_message: alertMsg } }];

const input = $input.first().json;

// === Configuration ===
// Set your OpenRouter API key in n8n Environment Variables as OPENROUTER_API_KEY
// Or replace the line below with your actual key
const apiKey = "$OPENROUTER_API_KEY";

if (!apiKey || apiKey === "$OPENROUTER_API_KEY") {
  return [{ json: { phone: input.phone, raw_message: input.raw_message, intent: "unknown", confidence: 0, reply: "", escalate: true, reason: "api_key_not_configured" } }];
}

try {
  const response = await $http.post(
    "https://openrouter.ai/api/v1/chat/completions",
    {
      model: "qwen/qwen2.5-72b-instruct",
      messages: [
        {
          role: "system",
          content: "You are a customer care bot for a boutique. Analyze the user message and return ONLY valid JSON with these fields: intent (string), confidence (number 0-1), reply (string in Hindi/English), escalate (boolean), reason (string). No markdown, no extra text."
        },
        {
          role: "user",
          content: "Session key: " + input.phone + "\nUser message: " + input.raw_message
        }
      ]
    },
    {
      headers: {
        "Authorization": "Bearer " + apiKey,
        "Content-Type": "application/json",
        "HTTP-Referer": "https://n8n.workflow",
        "X-Title": "WhatsApp Customer Care"
      }
    }
  );

  let content = "";
  if (typeof response === "object" && response.data) {
    content = response.data.choices[0].message.content;
  } else if (typeof response === "object" && response.body) {
    content = response.body.choices[0].message.content;
  }

  let parsed = {};
  try { parsed = JSON.parse(content); } catch (e) {}

  return [{
    json: {
      phone: input.phone,
      raw_message: input.raw_message,
      intent: parsed.intent || "unknown",
      confidence: typeof parsed.confidence === "number" ? parsed.confidence : 0,
      reply: parsed.reply || "",
      escalate: parsed.escalate === true,
      reason: parsed.reason || ""
    }
  }];
} catch (error) {
  return [{
    json: {
      phone: input.phone,
      raw_message: input.raw_message,
      intent: "unknown",
      confidence: 0,
      reply: "",
      escalate: true,
      reason: "api_error: " + (error.message || "unknown")
    }
  }];
}

const input = $input.first().json;
const alertMsg = "AI ESCALATE: " + (input.intent || "unknown") + " (confidence: " + (input.confidence || 0) + ")
Reason: " + (input.reason || "low confidence") + "
Phone: " + input.phone + "
Message: " + input.raw_message;
return [{ json: { phone: input.phone, alert_message: alertMsg } }];
